import os

def create_files():
    files = {
        "mcp/requirements.txt": "fastapi\nuvicorn\npydantic\nhttpx\npython-dotenv\n",
        "mcp/server.py": "from fastapi import FastAPI, Depends, HTTPException, Security\nfrom fastapi.security import APIKeyHeader\nfrom pydantic import BaseModel\nfrom typing import Any, Dict\nimport httpx\nimport asyncio\nfrom tools.registry import tool_registry\n\napp = FastAPI(title=\"TrustGuardAI MCP Server\", version=\"1.0.0\")\n\nAPI_KEY_NAME = \"X-MCP-API-Key\"\napi_key_header = APIKeyHeader(name=API_KEY_NAME, auto_error=True)\nVALID_API_KEY = \"mcp-super-secret-key\"\n\nasync def verify_api_key(api_key: str = Security(api_key_header)):\n    if api_key != VALID_API_KEY:\n        raise HTTPException(status_code=403, detail=\"Could not validate MCP API KEY\")\n    return api_key\n\nclass ToolRequest(BaseModel):\n    tool_name: str\n    parameters: Dict[str, Any]\n\n@app.post(\"/execute\")\nasync def execute_tool(request: ToolRequest, api_key: str = Depends(verify_api_key)):\n    if request.tool_name not in tool_registry:\n        raise HTTPException(status_code=404, detail=f\"Tool {request.tool_name} not found\")\n        \n    tool = tool_registry[request.tool_name]\n    try:\n        # Validate input schema\n        validated_input = tool.input_schema(**request.parameters)\n        # Execute with retry policy & caching\n        result = await tool.execute_with_retry(validated_input)\n        return {\"status\": \"success\", \"data\": result}\n    except Exception as e:\n        raise HTTPException(status_code=500, detail=str(e))\n\n@app.get(\"/tools\")\nasync def list_tools(api_key: str = Depends(verify_api_key)):\n    return {\"tools\": list(tool_registry.keys())}\n",
        "mcp/tools/base.py": "from abc import ABC, abstractmethod\nfrom pydantic import BaseModel\nimport logging\nimport asyncio\n\nlogger = logging.getLogger(\"mcp_tool\")\n\nclass BaseTool(ABC):\n    name: str\n    input_schema: type[BaseModel]\n    output_schema: type[BaseModel]\n    \n    def __init__(self):\n        self.max_retries = 3\n        self._cache = {}\n        \n    @abstractmethod\n    async def execute(self, params: BaseModel) -> BaseModel:\n        pass\n        \n    async def execute_with_retry(self, params: BaseModel) -> dict:\n        # Simple caching mechanism based on input dump\n        cache_key = params.model_dump_json()\n        if cache_key in self._cache:\n            logger.info(f\"[{self.name}] Cache hit\")\n            return self._cache[cache_key]\n            \n        for attempt in range(self.max_retries):\n            try:\n                logger.info(f\"[{self.name}] Executing attempt {attempt + 1}\")\n                result = await asyncio.wait_for(self.execute(params), timeout=10.0)\n                out_dict = result.model_dump()\n                self._cache[cache_key] = out_dict\n                return out_dict\n            except Exception as e:\n                logger.error(f\"[{self.name}] Error: {e}\")\n                if attempt == self.max_retries - 1:\n                    raise e\n                await asyncio.sleep(2 ** attempt) # Exponential backoff\n",
        "mcp/tools/implementations.py": "from .base import BaseTool\nfrom pydantic import BaseModel, Field\nfrom typing import List, Optional\nimport httpx\nimport os\n\n# --- 1. WHOIS Lookup ---\nclass WhoisInput(BaseModel):\n    domain: str\nclass WhoisOutput(BaseModel):\n    age_days: int\n    registrar: str\n    \nclass WhoisTool(BaseTool):\n    name = \"whois_lookup\"\n    input_schema = WhoisInput\n    output_schema = WhoisOutput\n    async def execute(self, params: WhoisInput) -> WhoisOutput:\n        # Mocked external API call\n        return WhoisOutput(age_days=15, registrar=\"GoDaddy\")\n\n# --- 2. SSL Checker ---\nclass SSLInput(BaseModel):\n    domain: str\nclass SSLOutput(BaseModel):\n    is_valid: bool\n    issuer: str\n\nclass SSLTool(BaseTool):\n    name = \"ssl_checker\"\n    input_schema = SSLInput\n    output_schema = SSLOutput\n    async def execute(self, params: SSLInput) -> SSLOutput:\n        return SSLOutput(is_valid=True, issuer=\"Let's Encrypt\")\n\n# --- 3. VirusTotal Lookup ---\nclass VTInput(BaseModel):\n    url: str\nclass VTOutput(BaseModel):\n    malicious_votes: int\n\nclass VirusTotalTool(BaseTool):\n    name = \"virustotal_lookup\"\n    input_schema = VTInput\n    output_schema = VTOutput\n    async def execute(self, params: VTInput) -> VTOutput:\n        return VTOutput(malicious_votes=3 if \"paypal\" in params.url.lower() else 0)\n\n# --- 4. Google Safe Browsing ---\nclass GSBInput(BaseModel):\n    url: str\nclass GSBOutput(BaseModel):\n    is_safe: bool\n\nclass GoogleSafeBrowsingTool(BaseTool):\n    name = \"google_safe_browsing\"\n    input_schema = GSBInput\n    output_schema = GSBOutput\n    async def execute(self, params: GSBInput) -> GSBOutput:\n        return GSBOutput(is_safe=False if \"fake\" in params.url else True)\n\n# --- 5. OpenPhish ---\nclass OpenPhishInput(BaseModel):\n    url: str\nclass OpenPhishOutput(BaseModel):\n    found: bool\n\nclass OpenPhishTool(BaseTool):\n    name = \"openphish_lookup\"\n    input_schema = OpenPhishInput\n    output_schema = OpenPhishOutput\n    async def execute(self, params: OpenPhishInput) -> OpenPhishOutput:\n        return OpenPhishOutput(found=False)\n\n# --- 6. URLHaus ---\nclass URLHausInput(BaseModel):\n    url: str\nclass URLHausOutput(BaseModel):\n    status: str\n\nclass URLHausTool(BaseTool):\n    name = \"urlhaus_lookup\"\n    input_schema = URLHausInput\n    output_schema = URLHausOutput\n    async def execute(self, params: URLHausInput) -> URLHausOutput:\n        return URLHausOutput(status=\"offline\")\n\n# --- 7. DNS Lookup ---\nclass DNSInput(BaseModel):\n    domain: str\nclass DNSOutput(BaseModel):\n    records: List[str]\n\nclass DNSTool(BaseTool):\n    name = \"dns_lookup\"\n    input_schema = DNSInput\n    output_schema = DNSOutput\n    async def execute(self, params: DNSInput) -> DNSOutput:\n        return DNSOutput(records=[\"192.168.1.1\", \"10.0.0.1\"])\n\n# --- 8. Brand Similarity ---\nclass BrandInput(BaseModel):\n    domain: str\nclass BrandOutput(BaseModel):\n    impersonated_brand: Optional[str]\n    similarity_score: float\n\nclass BrandSimilarityTool(BaseTool):\n    name = \"brand_similarity\"\n    input_schema = BrandInput\n    output_schema = BrandOutput\n    async def execute(self, params: BrandInput) -> BrandOutput:\n        if \"paypa\" in params.domain:\n            return BrandOutput(impersonated_brand=\"PayPal\", similarity_score=0.95)\n        return BrandOutput(impersonated_brand=None, similarity_score=0.0)\n\n# --- 9. Official Website Finder ---\nclass OfficialWebsiteInput(BaseModel):\n    brand: str\nclass OfficialWebsiteOutput(BaseModel):\n    url: str\n\nclass OfficialWebsiteFinderTool(BaseTool):\n    name = \"official_website_finder\"\n    input_schema = OfficialWebsiteInput\n    output_schema = OfficialWebsiteOutput\n    async def execute(self, params: OfficialWebsiteInput) -> OfficialWebsiteOutput:\n        return OfficialWebsiteOutput(url=f\"https://www.{params.brand.lower()}.com\")\n\n# --- 10. Threat Aggregator ---\nclass ThreatAggregatorInput(BaseModel):\n    flags: List[str]\nclass ThreatAggregatorOutput(BaseModel):\n    risk_score: float\n    level: str\n\nclass ThreatAggregatorTool(BaseTool):\n    name = \"threat_aggregator\"\n    input_schema = ThreatAggregatorInput\n    output_schema = ThreatAggregatorOutput\n    async def execute(self, params: ThreatAggregatorInput) -> ThreatAggregatorOutput:\n        score = min(len(params.flags) * 25.0, 100.0)\n        level = \"Critical\" if score > 75 else \"High\" if score > 50 else \"Low\"\n        return ThreatAggregatorOutput(risk_score=score, level=level)\n\n# --- 11. Report Generator ---\nclass ReportGenInput(BaseModel):\n    target: str\n    score: float\nclass ReportGenOutput(BaseModel):\n    markdown_report: str\n\nclass ReportGeneratorTool(BaseTool):\n    name = \"report_generator\"\n    input_schema = ReportGenInput\n    output_schema = ReportGenOutput\n    async def execute(self, params: ReportGenInput) -> ReportGenOutput:\n        return ReportGenOutput(markdown_report=f\"# Analysis for {params.target}\\nScore: {params.score}\")\n\n# --- 12. Embedding Generator ---\nclass EmbeddingInput(BaseModel):\n    text: str\nclass EmbeddingOutput(BaseModel):\n    vector: List[float]\n\nclass EmbeddingGeneratorTool(BaseTool):\n    name = \"embedding_generator\"\n    input_schema = EmbeddingInput\n    output_schema = EmbeddingOutput\n    async def execute(self, params: EmbeddingInput) -> EmbeddingOutput:\n        # Mock 768-dim vector\n        return EmbeddingOutput(vector=[0.1] * 768)\n",
        "mcp/tools/registry.py": "from .implementations import (\n    WhoisTool, SSLTool, VirusTotalTool, GoogleSafeBrowsingTool, \n    OpenPhishTool, URLHausTool, DNSTool, BrandSimilarityTool, \n    OfficialWebsiteFinderTool, ThreatAggregatorTool, \n    ReportGeneratorTool, EmbeddingGeneratorTool\n)\n\ntool_registry = {\n    \"whois_lookup\": WhoisTool(),\n    \"ssl_checker\": SSLTool(),\n    \"virustotal_lookup\": VirusTotalTool(),\n    \"google_safe_browsing\": GoogleSafeBrowsingTool(),\n    \"openphish_lookup\": OpenPhishTool(),\n    \"urlhaus_lookup\": URLHausTool(),\n    \"dns_lookup\": DNSTool(),\n    \"brand_similarity\": BrandSimilarityTool(),\n    \"official_website_finder\": OfficialWebsiteFinderTool(),\n    \"threat_aggregator\": ThreatAggregatorTool(),\n    \"report_generator\": ReportGeneratorTool(),\n    \"embedding_generator\": EmbeddingGeneratorTool(),\n}\n"
    }

    for path, content in files.items():
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)

if __name__ == "__main__":
    create_files()
    print("MCP Server Stage 8 scaffolded.")
